func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    for jj := range oris {
        var bestIdx int = -1
        var bestCostDelta float64 = 0.0
        var originalCosts [MAXASSIGNS]float64
        for i := 0; i < dispatch.AssignsLen; i++ {
            originalCosts[i] = dispatch.Assigns[i].Cost
        }
        for idx := 0; idx < dispatch.AssignsLen; idx++ {
            assign := &dispatch.Assigns[idx]
            savedCost := assign.Cost
            ok := assign.AddShip(total_ship+jj, oris[jj], dess[jj])
            if !ok {
                continue
            }
            assign.GenRoute()
            if assign.Cost < 0 {
                assign.RemoveShip(total_ship + jj)
                assign.GenRoute()
                continue
            }
            costIncrease := assign.Cost - savedCost
            if bestIdx == -1 || costIncrease < bestCostDelta {
                bestIdx = idx
                bestCostDelta = costIncrease
            }
            assign.RemoveShip(total_ship + jj)
            assign.GenRoute()
        }
        if bestIdx != -1 {
            dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
            dispatch.Assigns[bestIdx].GenRoute()
        } else {
            if dispatch.AssignsLen < MAXASSIGNS {
                newIdx := dispatch.AssignsLen
                dispatch.Assigns[newIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
                dispatch.Assigns[newIdx].GenRoute()
                dispatch.AssignsLen++
            } else {
                for idx := 0; idx < dispatch.AssignsLen; idx++ {
                    if dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
                        dispatch.Assigns[idx].GenRoute()
                        break
                    }
                }
            }
        }
    }
    dispatch.RenewnTotalCost()
    return dispatch

