Modified cheapest-insertion with parallel feasibility sampling across existing routes and reserved empty slots, using multi-candidate cost comparison and safe forced initialization when all trials fail.}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	type cand struct {
		idx       int
		isEmpty   bool
		costDelta float64
		valid     bool
	}
	for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx
		candidates := make([]cand, 0, dispatch.AssignsLen+1)
		savedCosts := [MAXASSIGNS]float64{}
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedCosts[i] = dispatch.Assigns[i].Cost
		}
		for i := 0; i < dispatch.AssignsLen; i++ {
			a := &dispatch.Assigns[i]
			oldCost := a.Cost
			ok := a.AddShip(shipID, ori, des)
			if ok {
				a.GenRoute()
				newCost := a.Cost
				if newCost >= 0 {
					candidates = append(candidates, cand{i, false, newCost - oldCost, true})
				}
			}
			a.RemoveShip(shipID)
			a.GenRoute()
			a.Cost = savedCosts[i]
		}
		emptySlot := -1
		for i := 0; i < MAXASSIGNS; i++ {
			if i >= dispatch.AssignsLen {
				emptySlot = i
				break
			}
		}
		if emptySlot != -1 {
			a := &dispatch.Assigns[emptySlot]
			oldCost := a.Cost
			ok := a.AddShip(shipID, ori, des)
			if ok {
				a.GenRoute()
				newCost := a.Cost
				if newCost >= 0 {
					candidates = append(candidates, cand{emptySlot, true, newCost - oldCost, true})
				}
			}
			a.RemoveShip(shipID)
			a.GenRoute()
			a.Cost = oldCost
		}
		bestCand := cand{-1, false, 1e100, false}
		for _, c := range candidates {
			if c.valid && c.costDelta < bestCand.costDelta {
				bestCand = c
			}
		}
		targetIdx := -1
		if bestCand.valid {
			targetIdx = bestCand.idx
			if bestCand.isEmpty && targetIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = targetIdx + 1
			}
			a := &dispatch.Assigns[targetIdx]
			a.AddShip(shipID, ori, des)
			a.GenRoute()
		} else {
			newIdx := dispatch.AssignsLen
			if newIdx < MAXASSIGNS {
				a := &dispatch.Assigns[newIdx]
				a.AddShip(shipID, ori, des)
				a.GenRoute()
				dispatch.AssignsLen++
				targetIdx = newIdx
			}
		}
		if targetIdx == -1 {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				a := &dispatch.Assigns[fallbackIdx]
				a.AddShip(shipID, ori, des)
				a.GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

